requests.postData:
{"query":"query getProcessorLastVersion($processor: String!) {
  processor_status(where: {processor: {_eq: $processor}}) {
    last_success_version
  }
}","variables":{"processor":"coin_processor"},"operationName":"getProcessorLastVersion"}

{"query":"query getAccountCoinActivity($address: String!, $offset: Int, $limit: Int) {
  coin_activities(
    where: {owner_address: {_eq: $address}}
    limit: $limit
    offset: $offset
    order_by: [{transaction_version: desc}, {event_account_address: desc}, {event_creation_number: desc}, {event_sequence_number: desc}]
  ) {
    ...CoinActivityFields
  }
}

fragment CoinActivityFields on coin_activities {
  transaction_timestamp
  transaction_version
  amount
  activity_type
  coin_type
  is_gas_fee
  is_transaction_success
  event_account_address
  event_creation_number
  event_sequence_number
  entry_function_id_str
  block_height
}","variables":{"address":"0xf26cbb3127abc72631e9236beacd595092126b5629ec53300e8ff1bb79f6cc5f","limit":20,"offset":0},"operationName":"getAccountCoinActivity"}

